SELECT relname, n_tup_ins, n_tup_upd, n_tup_del, n_live_tup, n_dead_tup
FROM pg_stat_user_tables 
WHERE relname = 'bookings';

SELECT indexname, idx_tup_read, idx_tup_fetch
FROM pg_stat_user_indexes 
WHERE relname = 'bookings';

SELECT indexrelname, idx_tup_read, idx_tup_fetch
FROM pg_stat_user_indexes 
WHERE relname = 'bookings';

SELECT schemaname, tablename, last_vacuum, last_autovacuum, vacuum_count, autovacuum_count
FROM pg_stat_user_tables 
WHERE tablename = 'bookings';

SELECT schemaname, relname, last_vacuum, last_autovacuum, vacuum_count, autovacuum_count
FROM pg_stat_user_tables 
WHERE relname = 'bookings';

SELECT pg_size_pretty(pg_total_relation_size('bookings.bookings')) AS total_size,
       pg_size_pretty(pg_relation_size('bookings.bookings')) AS table_size,
       pg_size_pretty(pg_indexes_size('bookings.bookings')) AS indexes_size;

SELECT pg_stat_user_tables.n_tup_upd, pg_stat_user_tables.n_dead_tup
FROM pg_stat_user_tables 
WHERE relname = 'bookings';

